async (params, browser) => {
  // Open WhatsApp chat with number
  await browser.open('https://web.whatsapp.com/send')

  // Wait for chat to open
  await browser.waitForSelector('div[contenteditable=\'true\'][data-tab=\'10\'], footer div[contenteditable=\'true\']', 30000)

  // Let chat load
  await browser.wait(3000)

  // Send message
  const result = await browser.evaluate(`const sendBtn = document.querySelector('span[data-icon="send"], button[aria-label="Send"]'); if (sendBtn) { sendBtn.closest('button')?.click() || sendBtn.click(); await new Promise(r => setTimeout(r, 1500)); return { success: true, phone: '' + params.phone_number + '', message: params.message }; } const msgBox = document.querySelector('div[contenteditable="true"][data-tab="10"]') || document.querySelector('footer div[contenteditable="true"]'); if (msgBox) { msgBox.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true })); await new Promise(r => setTimeout(r, 1500)); return { success: true, phone: '' + params.phone_number + '', message: params.message }; } return { success: false, message: 'Could not send - chat may not have loaded properly' }`)

  return result
}
